// FunГ§ГЈo para desenhar onda
function drawWave(doc, startY, color, amplitude, frequency) {
    doc.setDrawColor(color);
    doc.setFillColor(color);
    doc.setLineWidth(0);

    // Path complexo com curvas
    let path = `M 0 ${startY}`;
    for (let x = 0; x <= 210; x += 5) {
        let y = startY + Math.sin(x / frequency) * amplitude;
        path += ` L ${x} ${y}`;
    }
    path += ` L 210 297 L 0 297 Z`;

    doc.path(path).fill();
}
```

